<?php
require_once __DIR__ . '/../../helpers.php'; require_once __DIR__ . '/../../mail.php';
if ($_SERVER['REQUEST_METHOD'] !== 'POST') pw_error('Method not allowed.',405);
$admin=pw_require_permission('mail.campaigns.send');$input=pw_input();pw_require_csrf($input);$id=(int)($input['id']??0);$db=pw_db();
$c=$db->prepare("SELECT * FROM mail_campaigns WHERE id=? AND status IN ('ready','sending','paused')");$c->execute([$id]);$campaign=$c->fetch();if(!$campaign)pw_error('Prepare this campaign before sending.',409);
$rows=$db->prepare("SELECT r.* FROM mail_campaign_recipients r JOIN users u ON u.id=r.user_id WHERE r.campaign_id=? AND r.status='pending' AND u.newsletter_subscribed=1 LIMIT 25");$rows->execute([$id]);$rows=$rows->fetchAll();
foreach($rows as $r){$url='https://thepantheonwars.com/api/newsletter-subscription/unsubscribe.php?u='.$r['user_id'].'&t='.pw_newsletter_unsubscribe_token($r['user_id'],$r['recipient_email']);$html=$campaign['html_body'].'<p style="font-size:12px">To unsubscribe, <a href="'.$url.'">click here</a>.</p>';$text=$campaign['text_body']."\n\nUnsubscribe: ".$url;$out=pw_send_campaign_email($r['recipient_email'],$campaign['subject'],$html,$text);$db->prepare("UPDATE mail_campaign_recipients SET status=?,detail=?,sent_at=NOW() WHERE id=?")->execute([$out['sent']?'accepted':'failed',$out['reason'],$r['id']]);}
$pending=$db->prepare("SELECT COUNT(*) c FROM mail_campaign_recipients WHERE campaign_id=? AND status='pending'");$pending->execute([$id]);$left=(int)$pending->fetch()['c'];$db->prepare("UPDATE mail_campaigns SET status=?,accepted_count=(SELECT COUNT(*) FROM mail_campaign_recipients WHERE campaign_id=? AND status='accepted'),failed_count=(SELECT COUNT(*) FROM mail_campaign_recipients WHERE campaign_id=? AND status='failed'),sent_by=?,sent_at=IF(?=0,NOW(),sent_at) WHERE id=?")->execute([$left?'sending':'sent',$id,$id,$admin['id'],$left,$id]);pw_log_admin_activity('mail_campaign_batch_sent','Sent campaign batch for #'.$id.'.',$admin);pw_json(['ok'=>true,'remaining'=>$left]);
